SELECT SUM(site_area) AS total_active_site_area
FROM pollution_sites
WHERE operational_status = 'Active';

SELECT description
FROM development_types
WHERE development_type = 'Low Intensity';

SELECT site_name, pollution_level
FROM pollution_sites
WHERE pollution_level = (SELECT MAX(pollution_level) FROM pollution_sites);

SELECT operational_status, site_area
FROM pollution_sites
WHERE site_area = (SELECT MAX(site_area) FROM pollution_sites);

SELECT site_name, location, operational_status
FROM pollution_sites
WHERE site_id = 0;

SELECT user_id, AVG(predicted_mortality_rate) AS avg_predicted_mortality_rate
FROM scenario_models
GROUP BY user_id;

SELECT description
FROM forest_types
WHERE forest_type = 'Deciduous Forest';

SELECT severity, COUNT(site_id) AS site_count, MAX(site_area) AS max_area
FROM pollution_sites
GROUP BY severity;
